/**
 * @summary Get family dashboard data (for authorized contacts)
 */
export const getGetFamilyDashboardUrl = (params: GetFamilyDashboardParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/family/dashboard?${stringifiedParams}`
    : `/api/family/dashboard`;
};

export const getFamilyDashboard = async (
  params: GetFamilyDashboardParams,
  options?: RequestInit,
): Promise<FamilyDashboard> => {
  return customFetch<FamilyDashboard>(getGetFamilyDashboardUrl(params), {
    ...options,
    method: "GET",
  });
};

